CREATE TABLE RESTAURANT_ANALYSIS (
    Name VARCHAR2(255),
    City VARCHAR2(255),
    Speciality_1 VARCHAR2(255),
    Speciality_2 VARCHAR2(255),
    AvgDinnerPrice NUMBER,
    AvgLunchPrice NUMBER,
    TotalRating FLOAT,
    DinnerRating FLOAT,
    LunchRating FLOAT,
    Lat FLOAT,
    Long FLOAT,
    Has_Table_booking VARCHAR2(255),
    Has_Online_delivery VARCHAR2(255),
    Votes NUMBER
);

